const express = require('express');
const router = express.Router();

// Assuming req.user is an object with 'id' property
router.get('/profile', (req, res) => {
  const userId = req.user.id;
  res.json({ id: userId, name: req.user.name }); // Replace 'name' with the actual field in your user data
});

module.exports = router;